$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$BRANCH = "copilot/edburns28-python-agent-detail-view"
$PR_NUMBER = "48"

# Poll until the CCA run completes
$TIMEOUT = 900
$INTERVAL = 30
$ELAPSED = 0

while ($ELAPSED -lt $TIMEOUT) {
    $runs = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion 2>$null | ConvertFrom-Json
    $ccaRun = $runs | Where-Object { $_.name -eq "Running Copilot cloud agent" -and $_.status -eq "in_progress" }

    if (-not $ccaRun) {
        Write-Host "CCA run completed after $ELAPSED seconds"
        # Show all runs
        $runs | ForEach-Object { Write-Host "Run $($_.databaseId): $($_.name) - $($_.status) - $($_.conclusion)" }
        break
    }

    Write-Host "CCA still running... $ELAPSED seconds elapsed"
    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if ($ELAPSED -ge $TIMEOUT) {
    Write-Host "TIMEOUT: CCA still running after $TIMEOUT seconds"
}

